    private List<Message> loadMemory(String chatSessionId) {
        int messageLength = resolveRuntimeMessageWindow(agentConfig);
        List<ChatMessageDTO> chatMessages = chatMessageFacadeService.getChatMessagesBySessionIdRecently(chatSessionId, messageLength);
        chatMessages = sanitizeToolCallHistory(chatMessages);

        String persistedSummary = loadPersistedSummary(chatSessionId);
        String compressedSummary = persistedSummary;
        if (chatMessages.size() > messageLength) {
            int splitIndex = chatMessages.size() - messageLength;
            List<ChatMessageDTO> oldMessages = new ArrayList<>(chatMessages.subList(0, splitIndex));
            List<ChatMessageDTO> recentMessages = new ArrayList<>(chatMessages.subList(splitIndex, chatMessages.size()));
            recentMessages = sanitizeToolCallHistory(recentMessages);
            String incrementalSummary = summarizeOldMessages(oldMessages);
            compressedSummary = mergeSummaries(persistedSummary, incrementalSummary);
            savePersistedSummary(chatSessionId, compressedSummary);
            chatMessages = recentMessages;
            log.info("Memory compression applied for session={}, oldMessages={}, recentMessages={}",
                    chatSessionId, oldMessages.size(), recentMessages.size());
        }

        List<Message> memory = new ArrayList<>();
        if (StringUtils.hasText(compressedSummary)) {
            memory.add(new SystemMessage(compressedSummary));
        }
        for (ChatMessageDTO chatMessageDTO : chatMessages) {
            switch (chatMessageDTO.getRole()) {
                case SYSTEM:
                    if (!StringUtils.hasLength(chatMessageDTO.getContent())) {
                        continue;
                    }
                    memory.add(0, new SystemMessage(chatMessageDTO.getContent()));
                    break;
                case USER:
                    if (!StringUtils.hasLength(chatMessageDTO.getContent())) {
                        continue;
                    }
                    memory.add(new UserMessage(chatMessageDTO.getContent()));
                    break;
                case ASSISTANT:
                    memory.add(AssistantMessage.builder()
                            .content(chatMessageDTO.getContent())
                            .toolCalls(safeToolCalls(chatMessageDTO))
                            .build());
                    break;
                case TOOL:
                    ToolResponseMessage.ToolResponse toolResponse = safeToolResponse(chatMessageDTO);
                    if (toolResponse == null) {
                        log.warn("Skipping malformed TOOL message, chatMessageId={}", chatMessageDTO.getId());
                        continue;
                    }
                    memory.add(ToolResponseMessage.builder()
                            .responses(List.of(toolResponse))
                            .build());
                    break;
                default:
                    log.error("Unsupported message role: {}, content={}",
                            chatMessageDTO.getRole().getRole(), chatMessageDTO.getContent());
                    throw new IllegalStateException("Unsupported message role");
            }
        }
        return memory;
    }

    private String loadPersistedSummary(String chatSessionId) {
        try {
            ChatMemorySummary summary = chatMemorySummaryMapper.selectBySessionId(chatSessionId);
            if (summary == null || !StringUtils.hasText(summary.getSummaryText())) {
                return null;
            }
            return summary.getSummaryText();
        } catch (Exception e) {
            log.warn("Load memory summary failed, sessionId={}, err={}", chatSessionId, e.getMessage());
            return null;
        }
    }

    private void savePersistedSummary(String chatSessionId, String summaryText) {
        if (!StringUtils.hasText(summaryText)) {
            return;
        }
        try {
            chatMemorySummaryMapper.upsertSummary(chatSessionId, summaryText);
        } catch (Exception e) {
            log.warn("Save memory summary failed, sessionId={}, err={}", chatSessionId, e.getMessage());
        }
    }

    private String mergeSummaries(String existingSummary, String incrementalSummary) {
        if (!StringUtils.hasText(existingSummary)) {
            return incrementalSummary;
        }
        if (!StringUtils.hasText(incrementalSummary)) {
            return existingSummary;
        }
        String merged = (existingSummary.trim() + "\n\n" + incrementalSummary.trim()).trim();
        if (merged.length() > llmSummaryOutputMaxChars) {
            return merged.substring(0, llmSummaryOutputMaxChars);
        }
        return merged;
    }

