    private String summarizeOldMessages(List<ChatMessageDTO> oldMessages) {
        String ruleSummary = buildRuleBasedSummary(oldMessages);
        if (!llmSummaryEnabled) {
            return ruleSummary;
        }
        String llmSummary = summarizeWithLlm(oldMessages, ruleSummary);
        return StringUtils.hasText(llmSummary) ? llmSummary : ruleSummary;
    }

