    private String buildSummaryTranscript(List<ChatMessageDTO> oldMessages) {
        int start = Math.max(0, oldMessages.size() - llmSummaryMaxMessages);
        List<String> rows = new ArrayList<>();
        for (int i = start; i < oldMessages.size(); i++) {
            ChatMessageDTO msg = oldMessages.get(i);
            if (msg == null || msg.getRole() == null) {
                continue;
            }
            String role = msg.getRole().getRole();
            String content = trimForLlmSummary(msg.getContent(), LLM_SUMMARY_INPUT_SNIPPET_LIMIT);
            if (msg.getRole() == ChatMessageDTO.RoleType.TOOL) {
                String toolName = resolveToolName(msg);
                if (StringUtils.hasText(toolName)) {
                    rows.add("[%s] tool=%s content=%s".formatted(role, toolName, content));
                    continue;
                }
            }
            rows.add("[%s] %s".formatted(role, content));
        }
        return String.join("\n", rows);
    }

