    private String trimForLlmSummary(String raw, int limit) {
        if (!StringUtils.hasText(raw)) {
            return "";
        }
        String normalized = raw.replaceAll("\\s+", " ").trim();
        if (normalized.length() <= limit) {
            return normalized;
        }
        int safeLimit = Math.max(32, Math.min(limit, LLM_SUMMARY_FALLBACK_OUTPUT_LIMIT));
        return normalized.substring(0, safeLimit) + "...";
    }

    private void addSummaryLine(List<String> lines, String prefix, String content) {
        if (lines.size() >= SUMMARY_MAX_ITEMS) {
            return;
        }
        String snippet = trimSnippet(content, SUMMARY_SNIPPET_LIMIT);
        if (!StringUtils.hasText(snippet)) {
            return;
        }
        lines.add("- " + prefix + ": " + snippet);
    }

