    public JChatMind create(String agentId, String chatSessionId) {
        Agent agent = loadAgent(agentId);
        AgentDTO agentConfig = toAgentConfig(agent);
        List<Message> memory = loadMemory(chatSessionId);

        List<KnowledgeBaseDTO> knowledgeBases = resolveRuntimeKnowledgeBases(agentConfig);
        List<Tool> runtimeTools = resolveRuntimeTools(agentConfig);
        List<ToolCallback> toolCallbacks = buildToolCallbacks(runtimeTools);

        Agent guardedAgent = Agent.builder()
                .id(agent.getId())
                .name(agent.getName())
                .description(agent.getDescription())
                .systemPrompt(buildGuardedSystemPrompt(agent.getSystemPrompt()))
                .model(agent.getModel())
                .allowedTools(agent.getAllowedTools())
                .allowedKbs(agent.getAllowedKbs())
                .chatOptions(agent.getChatOptions())
                .createdAt(agent.getCreatedAt())
                .updatedAt(agent.getUpdatedAt())
                .build();

        return buildAgentRuntime(guardedAgent, memory, knowledgeBases, toolCallbacks, chatSessionId);
    }
